package com.feer.cameralibre

import android.content.Context
import android.hardware.camera2.*
import android.media.MediaCodec
import android.media.MediaCodecInfo
import android.media.MediaFormat
import android.os.Handler
import android.os.HandlerThread
import android.util.Range
import android.view.Surface
import java.net.Socket
import java.nio.ByteBuffer

class H264StreamingEngine(private val context: Context) {
    private var cameraDevice: CameraDevice? = null
    private var mediaCodec: MediaCodec? = null
    private var encoderSurface: Surface? = null
    private var captureSession: CameraCaptureSession? = null
    private var socket: Socket? = null
    private var isRunning = false

    private val cameraThread = HandlerThread("CameraThread").apply { start() }
    private val cameraHandler = Handler(cameraThread.looper)
    private val codecThread = HandlerThread("CodecThread").apply { start() }
    private val codecHandler = Handler(codecThread.looper)

    fun start(
        cameraId: String,
        width: Int,
        height: Int,
        fps: Int,
        bitrate: Int,
        serverIp: String,
        serverPort: Int
    ) {
        isRunning = true

        // 1. Setup TCP socket in background
        Thread {
            socket = Socket(serverIp, serverPort)
        }.start()

        // 2. Configure MediaCodec with Surface input
        val format = MediaFormat.createVideoFormat(MediaFormat.MIMETYPE_VIDEO_AVC, width, height)
        format.setInteger(MediaFormat.KEY_COLOR_FORMAT, MediaCodecInfo.CodecCapabilities.COLOR_FormatSurface)
        format.setInteger(MediaFormat.KEY_BIT_RATE, bitrate)
        format.setInteger(MediaFormat.KEY_FRAME_RATE, fps)
        format.setInteger(MediaFormat.KEY_I_FRAME_INTERVAL, 1)

        mediaCodec = MediaCodec.createEncoderByType(MediaFormat.MIMETYPE_VIDEO_AVC)
        mediaCodec?.configure(format, null, null, MediaCodec.CONFIGURE_FLAG_ENCODE)
        encoderSurface = mediaCodec?.createInputSurface()
        mediaCodec?.start()

        // 3. Start NAL unit drainer
        codecHandler.post { drainEncoder() }

        // 4. Open Camera2 and target the encoder Surface
        val cameraManager = context.getSystemService(Context.CAMERA_SERVICE) as CameraManager
        cameraManager.openCamera(cameraId, object : CameraDevice.StateCallback() {
            override fun onOpened(camera: CameraDevice) {
                cameraDevice = camera
                val surfaces = mutableListOf<Surface>()
                encoderSurface?.let { surfaces.add(it) }

                camera.createCaptureSession(
                    surfaces,
                    object : CameraCaptureSession.StateCallback() {
                        override fun onConfigured(session: CameraCaptureSession) {
                            captureSession = session
                            val builder = camera.createCaptureRequest(CameraDevice.TEMPLATE_RECORD)
                            surfaces.forEach { builder.addTarget(it) }
                            builder.set(CaptureRequest.CONTROL_AE_TARGET_FPS_RANGE, Range(fps, fps))
                            session.setRepeatingRequest(builder.build(), null, cameraHandler)
                        }
                        override fun onConfigureFailed(session: CameraCaptureSession) {}
                    },
                    cameraHandler
                )
            }
            override fun onDisconnected(camera: CameraDevice) { stop() }
            override fun onError(camera: CameraDevice, error: Int) { stop() }
        }, cameraHandler)
    }

    private fun drainEncoder() {
        val info = MediaCodec.BufferInfo()
        while (isRunning) {
            val idx = mediaCodec?.dequeueOutputBuffer(info, 10000) ?: -1
            if (idx >= 0) {
                val buffer = mediaCodec?.getOutputBuffer(idx)
                if (buffer != null && socket?.isConnected == true) {
                    val chunk = ByteArray(info.size)
                    buffer.get(chunk)
                    // Write length-prefixed NAL unit to TCP
                    socket?.getOutputStream()?.apply {
                        write((chunk.size shr 24) and 0xFF)
                        write((chunk.size shr 16) and 0xFF)
                        write((chunk.size shr 8) and 0xFF)
                        write(chunk.size and 0xFF)
                        write(chunk)
                        flush()
                    }
                }
                mediaCodec?.releaseOutputBuffer(idx, false)
            }
        }
    }

    fun stop() {
        isRunning = false
        captureSession?.close()
        cameraDevice?.close()
        mediaCodec?.stop()
        mediaCodec?.release()
        encoderSurface?.release()
        socket?.close()
        cameraThread.quitSafely()
        codecThread.quitSafely()
    }
}

