class StreamingController {
  static const _channel = MethodChannel('com.feer.cameralibre/streaming');

  Future<bool> start({
    required String ip,
    required int port,
    required int width,
    required int height,
    required int fps,
    required int bitrate,
    required String cameraId,
  }) async {
    return await _channel.invokeMethod('start', {
      'cameraId': cameraId,
      'serverIp': ip,
      'serverPort': port,
      'width': width,
      'height': height,
      'fps': fps,
      'bitrate': bitrate,
    });
  }

  Future<bool> stop() async {
    return await _channel.invokeMethod('stop');
  }

  Future<Map> getStats() async {
    return await _channel.invokeMethod('getStats');
  }
}
